with open("/root/books/webapp/books.json") as f:
    books = json.load(f)

existing_ids = {b["id"] for b in books}
added = 0
for book in new_books:
    if book["id"] not in existing_ids:
        books.append(book)
        added += 1
        print(f"Добавлена: {book['id']} {book['title']}")

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))

print(f"Всего добавлено: {added}")
print(f"Итого книг: {len(books)}")
